@WebService(
        serviceName = "BankingTransactionsService",
        portName = "BankingTransactionsPort",
        endpointInterface = "com.bank.api.BankingTransactions",
        targetNamespace = "http://bank.example.com/transactions"
)
public class BankingTransactionsImpl implements BankingTransactions {

    @Resource
    private WebServiceContext wsContext;

    @Override
    public TransactionResponse processTransaction(TransactionRequest request) {
        if (request == null || isBlank(request.getTransactionId())) {
            return new TransactionResponse(null, "REJECTED", "Missing transactionId");
        }
        if (isBlank(request.getFromAccount()) || isBlank(request.getToAccount())) {
            return new TransactionResponse(request.getTransactionId(), "REJECTED", "Missing account details");
        }
        BigDecimal amount = request.getAmount();
        if (amount == null || amount.signum() <= 0) {
            return new TransactionResponse(request.getTransactionId(), "REJECTED", "Invalid amount");
        }
        if (isBlank(request.getCurrency())) {
            return new TransactionResponse(request.getTransactionId(), "REJECTED", "Missing currency");
        }
        return new TransactionResponse(request.getTransactionId(), "APPROVED", "Processed");
    }

    private static boolean isBlank(String s) {
        return s == null || s.trim().isEmpty();
    }
}

